ransmits: 0","Duration: 2.0s"]},{"x":614.3,"y":240.1,"color":"#16a34a","lines":["DOWNLOAD","06/05 20:18","Throughput: 209.59 Mbps","TCP retransmits: 1212","Duration: 2.0s"]},{"x":616.7,"y":54.1,"color":"#2563eb","lines":["UPLOAD","06/05 20:26","Throughput: 209.59 Mbps","TCP retransmits: 8","Duration: 2.0s"]},{"x":616.7,"y":240.1,"color":"#16a34a","lines":["DOWNLOAD","06/05 20:26","Throughput: 209.59 Mbps","TCP retransmits: 885","Duration: 2.0s"]},{"x":620.6,"y":54.1,"color":"#2563eb","lines":["UPLOAD","06/05 20:40","Throughput: 209.59 Mbps","TCP retransmits: 0","Duration: 2.0s"]},{"x":620.6,"y":240.1,"color":"#16a34a","lines":["DOWNLOAD","06/05 20:40","Throughput: 209.59 Mbps","TCP retransmits: 1749","Duration: 2.0s"]},{"x":624.0,"y":54.1,"color":"#2563eb","lines":["UPLOAD","06/05 20:51","Throughput: 209.59 Mbps","TCP retransmits: 0","Duration: 2.0s"]},{"x":624.0,"y":240.1,"color":"#16a34a","lines":["DOWNLOAD","06/05 20:51","Throughput: 209.59 Mbps","TCP retransmits: 609","Duration: 2.0s"]},{"x":624.4,"y":54.1,"color":"#2563eb","lines":["UPLOAD","06/05 20:53","Throughput: 209.59 Mbps","TCP retransmits: 3","Duration: 2.0s"]},{"x":624.4,"y":322.8,"color":"#16a34a","lines":["DOWNLOAD","06/05 20:53","Throughput: 83.87 Mbps","TCP retransmits: 119","Duration: 5.0s"]},{"x":626.7,"y":54.1,"color":"#2563eb","lines":["UPLOAD","06/05 21:01","Throughput: 209.59 Mbps","TCP retransmits: 1","Duration: 2.0s"]},{"x":626.8,"y":240.1,"color":"#16a34a","lines":["DOWNLOAD","06/05 21:01","Throughput: 209.59 Mbps","TCP retransmits: 1832","Duration: 2.0s"]},{"x":629.7,"y":54.1,"color":"#2563eb","lines":["UPLOAD","06/05 21:11","Throughput: 209.59 Mbps","TCP retransmits: 0","Duration: 2.0s"]},{"x":629.7,"y":240.1,"color":"#16a34a","lines":["DOWNLOAD","06/05 21:11","Throughput: 209.59 Mbps","TCP retransmits: 1193","Duration: 2.0s"]},{"x":733.5,"y":54.1,"color":"#2563eb","lines":["UPLOAD","06/06 03:11","Throughput: 209.59 Mbps","TCP retransmits: 6","Duration: 2.0s"]},{"x":733.5,"y":240.1,"color":"#16a34a","lines":["DOWNLOAD","06/06 03:11","Throughput: 209.59 Mbps","TCP retransmits: 786","Duration: 2.0s"]},{"x":837.3,"y":54.1,"color":"#2563eb","lines":["UPLOAD","06/06 09:11","Throughput: 209.59 Mbps","TCP retransmits: 0","Duration: 2.0s"]},{"x":837.3,"y":240.1,"color":"#16a34a","lines":["DOWNLOAD","06/06 09:11","Throughput: 209.59 Mbps","TCP retransmits: 665","Duration: 2.0s"]},{"x":941.1,"y":100.0,"color":"#2563eb","lines":["UPLOAD","06/06 15:11","Throughput: 139.75 Mbps","TCP retransmits: 1","Duration: 3.0s"]},{"x":941.2,"y":286.0,"color":"#16a34a","lines":["DOWNLOAD","06/06 15:11","Throughput: 139.76 Mbps","TCP retransmits: 797","Duration: 3.0s"]},{"x":1044.9,"y":123.1,"color":"#2563eb","lines":["UPLOAD","06/06 21:11","Throughput: 104.74 Mbps","TCP retransmits: 0","Duration: 4.0s"]},{"x":1045.0,"y":309.0,"color":"#16a34a","lines":["DOWNLOAD","06/06 21:11","Throughput: 104.83 Mbps","TCP retransmits: 3093","Duration: 4.0s"]}];
  if (!points.length) {
    return;
  }
  const bounds = {
    width: 1200,
    height: 460,
    left: 100,
    right: 155,
    top: 40.0,
    bottom: 82,
    tooltipWidth: 300,
    tooltipHeight: 108
  };
  const svg = document.documentElement;
  const hitArea = document.getElementById("inspect-hit-area");
  const cursorLine = document.getElementById("inspect-cursor-line");
  const cursorDot = document.getElementById("inspect-cursor-dot");
  const tooltip = document.getElementById("inspect-tooltip");
  const textNodes = Array.from({length: 5}, (_, index) => document.getElementById(`inspect-line-${index}`));
  let dragging = false;

  function clamp(value, minimum, maximum) {
    return Math.min(Math.max(value, minimum), maximum);
  }

  function eventPoint(event) {
    const matrix = svg.getScreenCTM();
    if (!matrix) {
      return null;
    }
    const point = svg.createSVGPoint();
    point.x = event.clientX;
    point.y = event.clientY;
    return point.matrixTransform(matrix.inverse());
  }

  function nearestPoint(x, y) {
    let best = points[0];
    let bestScore = Infinity;
    for (const point of points) {
      const dx = Math.abs(point.x - x);
      const dy = Math.abs(point.y - y);
      const score = dx + dy * 0.45;
      if (score < bestScore) {
        best = point;
        bestScore = score;
      }
    }
    return best;
  }

  function update(event) {
    const eventSvgPoint = eventPoint(event);
    if (!eventSvgPoint) {
      return;
    }
    const x = clamp(eventSvgPoint.x, bounds.left, bounds.width - bounds.right);
    const y = clamp(eventSvgPoint.y, bounds.top, bounds.height - bounds.bottom);
    const point = nearestPoint(x, y);
    const pointX = Number(point.x);
    const pointY = Number(point.y);
    const tooltipX = clamp(pointX + 12, bounds.left, bounds.width - bounds.right - bounds.tooltipWidth);
    const tooltipY = clamp(pointY - bounds.tooltipHeight - 12, bounds.top, bounds.height - bounds.bottom - bounds.tooltipHeight);

    cursorLine.setAttribute("x1", pointX);
    cursorLine.setAttribute("x2", pointX);
    cursorLine.setAttribute("visibility", "visible");
    cursorDot.setAttribute("cx", pointX);
    cursorDot.setAttribute("cy", pointY);
    cursorDot.setAttribute("fill", point.color || "#2563eb");
    cursorDot.setAttribute("visibility", "visible");

    const lines = point.lines || [];
    textNodes.forEach((node, index) => {
      node.textContent = lines[index] || "";
      node.setAttribute("visibility", lines[index] ? "visible" : "hidden");
      node.setAttribute("font-weight", index === 0 ? "700" : "400");
    });
    tooltip.setAttribute("transform", `translate(${tooltipX}, ${tooltipY})`);
    tooltip.setAttribute("visibility", "visible");
  }

  function hide() {
    if (dragging) {
      return;
    }
    cursorLine.setAttribute("visibility", "hidden");
    cursorDot.setAttribute("visibility", "hidden");
    tooltip.setAttribute("visibility", "hidden");
  }

  hitArea.addEventListener("pointermove", update);
  hitArea.addEventListener("pointerdown", (event) => {
    dragging = true;
    hitArea.setPointerCapture(event.pointerId);
    update(event);
  });
  hitArea.addEventListener("pointerup", (event) => {
    dragging = false;
    hitArea.releasePointerCapture(event.pointerId);
    update(event);
  });
  hitArea.addEventListener("pointercancel", () => {
    dragging = false;
    hide();
  });
  hitArea.addEventListener("pointerleave", hide);
})();
